"""lint_flags.py -- run in CI to validate flag registry entries."""
import re
import sys
from datetime import date
import yaml

KEY_PATTERN = re.compile(r'^[a-z0-9_]+\.[a-z0-9_]+\.[a-z0-9_]+$')
VALID_TYPES = {"release", "ops", "experiment", "permission"}
VALID_ENVS = {"staging", "production", "dev"}


def lint_flag(flag: dict) -> list:
    errors = []
    key = flag.get("key", "")
    if not KEY_PATTERN.match(key):
        errors.append(f"{key}: key must match <team>.<area>.<name>")
    if flag.get("type") not in VALID_TYPES:
        errors.append(f"{key}: type must be one of {VALID_TYPES}")
    if not flag.get("expires_at"):
        errors.append(f"{key}: expires_at is required")
    else:
        try:
            exp = date.fromisoformat(str(flag["expires_at"]))
            if exp < date.today():
                errors.append(f"{key}: expires_at is in the past -- clean up this flag")
        except ValueError:
            errors.append(f"{key}: expires_at must be ISO 8601 (YYYY-MM-DD)")
    if not flag.get("owner_team"):
        errors.append(f"{key}: owner_team is required")
    if not flag.get("description"):
        errors.append(f"{key}: description is required")
    unknown_envs = set(flag.get("environments", [])) - VALID_ENVS
    if unknown_envs:
        errors.append(f"{key}: unknown environments {unknown_envs}")
    return errors


def main():
    path = "flags/registry/agents.yaml"
    with open(path) as f:
        registry = yaml.safe_load(f)
    all_errors = []
    for flag in registry.get("flags", []):
        all_errors.extend(lint_flag(flag))
    if all_errors:
        for err in all_errors:
            print(f"ERROR: {err}", file=sys.stderr)
        sys.exit(1)
    print(f"OK: {len(registry['flags'])} flags validated")


if __name__ == "__main__":
    main()
